# ============================================================
#  PEDDAPALLI ROAD RISK — FASTAPI BACKEND
#  ML: Random Forest + Gradient Boosting (14-factor model)
#  Routing: Dijkstra on 550-node road network
#  Weather: Live Open-Meteo API
# ============================================================

from fastapi import FastAPI, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from contextlib import asynccontextmanager
from pydantic import BaseModel
from typing import Optional, List, Dict, Any
import numpy as np
import pandas as pd
import heapq
import requests
import warnings
import json
from collections import defaultdict
from io import StringIO
from datetime import datetime

warnings.filterwarnings("ignore")

from sklearn.model_selection import train_test_split, StratifiedKFold, cross_val_score
from sklearn.preprocessing import StandardScaler, LabelEncoder
from sklearn.ensemble import RandomForestClassifier, GradientBoostingClassifier
from sklearn.linear_model import LogisticRegression
from sklearn.metrics import f1_score, roc_auc_score, accuracy_score, precision_score, recall_score

# ─── FASTAPI SETUP ───────────────────────────────────────────
@asynccontextmanager
async def lifespan(app: FastAPI):
    await train_model()
    yield

app = FastAPI(title="Peddapalli Road Risk API", version="2.0", lifespan=lifespan)

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

# ─── PYDANTIC MODELS ─────────────────────────────────────────
class RouteRequest(BaseModel):
    source: str
    destination: str
    time: str = "now"

