@app.post("/api/route")
def compute_route(req: RouteRequest):
    """Compute route recommendations with ML risk scoring."""
    if not MODEL_STATE["ready"]:
        raise HTTPException(status_code=503, detail="Model not ready yet")

    # Resolve source and destination
    src = resolve_location(req.source)
    dst = resolve_location(req.destination)

    if not src:
        raise HTTPException(status_code=400, detail=f"Location '{req.source}' not found")
    if not dst:
        raise HTTPException(status_code=400, detail=f"Location '{req.destination}' not found")
    if src == dst:
        raise HTTPException(status_code=400, detail="Source and destination must be different")

    # Get live weather
    weather = get_current_weather(req.time)
    W  = weather["weather_condition"]
    IR = int(W == "rainy"); IF_ = int(W == "foggy"); IC = int(W == "cloudy")

    # Build network with current weather
    graph, seg_risks = build_full_network(W, IR, IF_, IC)

    if src not in graph or dst not in graph:
        raise HTTPException(status_code=400, detail=
            f"No route possible. Source: {src}, Destination: {dst}")

    # Compute 3 routes
    # 1. Safest (minimise risk)
    path_safe, trail_safe, _ = dijkstra(graph, src, dst, weight="risk")
    # 2. Fastest (minimise time)
    path_fast, trail_fast, _ = dijkstra(graph, src, dst, weight="time")
    # 3. Balanced
    path_bal,  trail_bal,  _ = dijkstra_balanced(graph, src, dst)

    routes = []
    for name_key, path, trail in [\
        ("safest", path_safe, trail_safe),\
        ("fastest", path_fast, trail_fast),\
        ("balanced", path_bal, trail_bal)\
    ]:
        if not path or len(path) < 2: continue
        km, mins, avg_risk = compute_route_stats(trail, seg_risks)
        label = risk_label(avg_risk)
        color = risk_color(avg_risk)
        segs_info = []
        for seg in path:
            if seg in seg_risks:
                sr = seg_risks[seg]
                segs_info.append({
                    "name": seg,
                    "risk_score": sr["risk_score"],
                    "risk_label": sr["risk_label"],
                    "risk_color": sr["risk_color"],
                    "road_type": sr["road_type"],
                    "mandal": sr["mandal"],
                    "lat": sr["lat"],
                    "lon": sr["lon"]
                })
        via_label = get_route_name(path, seg_risks)
        route_name_map = {
            "safest": f"Safest Route {via_label}",
            "fastest": f"Fastest Route {via_label}",
            "balanced": f"Shortest Route {via_label}"
        }
        routes.append({
            "id": name_key,
            "name": route_name_map[name_key],
            "path": path,
            "segments": segs_info,
            "km": km,
            "mins": int(mins) if mins else 0,
            "avg_risk": avg_risk,
            "risk_label": label,
            "risk_color": color,
            "n_segments": len(path)
        })

    if not routes:
        raise HTTPException(status_code=404, detail="No valid route found between locations")

    # Sort by risk
    routes.sort(key=lambda r: r["avg_risk"])

    # Best route = lowest risk among all computed
    best = routes[0]

    # Calculate risk reduction vs worst
    worst_risk = max(r["avg_risk"] for r in routes)
    best_risk  = best["avg_risk"]
    risk_cut   = round((1 - best_risk / worst_risk) * 100) if worst_risk > 0 else 0

    # Top risk segments across routes
    all_segs = {}
    for route in routes:
        for seg_info in route["segments"]:
            s = seg_info["name"]
            if s not in all_segs or seg_risks[s]["risk_score"] > all_segs[s]["risk_score"]:
                all_segs[s] = {
                    **seg_risks[s],
                    "name": s
                }
    top_risk_segs = sorted(all_segs.values(), key=lambda x: -x["risk_score"])[:7]

    # Distance (straight line) between src and dst
    sd = SEGMENT_DATA.get(src, {}); dd = SEGMENT_DATA.get(dst, {})
    direct_km = 0
    if sd and dd:
        lat_diff = (sd["lat"] - dd["lat"]) * 111
        lon_diff = (sd["lon"] - dd["lon"]) * 111
        direct_km = round((lat_diff**2 + lon_diff**2)**0.5, 1)

    time_label = "Day" if req.time in ("now","") else req.time

    return {
        "source": req.source,
        "destination": req.destination,
        "source_segment": src,
        "destination_segment": dst,
        "weather": weather,
        "direct_km": direct_km,
        "time_label": time_label,
        "routes": routes,
        "recommendation": {
            "route": best,
            "risk_cut_pct": risk_cut,
            "why": (f"The ML ensemble ({MODEL_STATE['best_name']}) scored "
                    f"{best['name']} at {best['avg_risk']:.3f} average accident risk "
                    f"— the lowest across {len(routes)} Dijkstra-computed routes. "
                    f"It is {risk_cut}% safer than the highest-risk route. "
                    f"No high-risk segments on this route."
                    if not any(s["risk_label"]=="High" for s in best["segments"])
                    else f"ML ensemble scored this route at {best['avg_risk']:.3f} risk. "
                         f"Some caution advised — see Explain tab for details.")
        },
        "top_risk_segments": top_risk_segs
    }

