@app.get("/api/risk_map")
def risk_map():
    """Return risk scores for all segments (for heatmap)."""
    if not MODEL_STATE["ready"]:
        raise HTTPException(status_code=503, detail="Model not ready")
    weather = get_current_weather()
    W = weather["weather_condition"]
    IR = int(W=="rainy"); IF_ = int(W=="foggy"); IC = int(W=="cloudy")
    _, seg_risks = build_full_network(W, IR, IF_, IC)
    result = []
    for seg, info in seg_risks.items():
        result.append({
            "name": seg,
            "lat": info["lat"],
            "lon": info["lon"],
            "risk_score": info["risk_score"],
            "risk_label": info["risk_label"],
            "road_type": info["road_type"],
            "mandal": info["mandal"]
        })
    result.sort(key=lambda x: -x["risk_score"])
    return {"segments": result[:50], "weather": weather}

